# ❌ ANTI-PATTERN: Naive Sequential Processing
class NaiveMatchAnalyzer:
    def analyze_delivery(self, pitch_video, crowd_audio):
        # Blocks on vision—audio queues indefinitely
        vision_result = self.vision_model.process(pitch_video)  # 800ms
        audio_result = self.audio_model.process(crowd_audio)    # 400ms
        return self.merge_results(vision_result, audio_result)   # Total: 1200ms

# ⚠️  PROBLEM: Dropped audio signals if vision delays; no modal prioritization

# ✅ BEST PRACTICE: Hierarchical Attention Pattern
import asyncio
from enum import Enum

class ModalPriority(Enum):
    CRITICAL = 0.9   # Safety signals (umpire calls, collision warnings)
    HIGH = 0.7       # Tactical (ball spin detection)
    NORMAL = 0.5     # Context (crowd reaction)

class ProductionMatchAnalyzer:
    def __init__(self):
        self.modal_weights = {}
        self.interrupt_queue = asyncio.Queue()

    async def analyze_delivery(self, pitch_video, crowd_audio, match_context):
        # Dynamic weighting based on context
        context_modality_importance = self._compute_importance(match_context)

        # Parallel processing with priority interrupts
        vision_task = asyncio.create_task(
            self._process_vision(pitch_video, context_modality_importance['vision'])
        )
        audio_task = asyncio.create_task(
            self._process_audio(crowd_audio, context_modality_importance['audio'])
        )

        # Audio can interrupt vision if critical (e.g., umpire shout)
        done, pending = await asyncio.wait(
            [vision_task, audio_task],
            timeout=0.5,  # 500ms SLA
            return_when=asyncio.FIRST_COMPLETED
        )

        partial_results = {t.get_name(): t.result() for t in done if not t.cancelled()}

        # Check for critical audio signals
        if 'audio' in partial_results and partial_results['audio']['confidence'] > 0.95:
            pending_tasks = asyncio.all_tasks() - done
            for task in pending_tasks:
                task.cancel()  # Interrupt vision processing

        # Wait for remaining with reduced timeout
        remaining = await asyncio.gather(*pending, return_exceptions=True)

        return self._hierarchical_merge(
            partial_results,
            context_modality_importance
        )

    def _compute_importance(self, match_context):
        # Adjust modal weights based on game state
        if match_context['critical_moment']:  # Last over, close match
            return {'vision': 0.8, 'audio': 0.6}  # Favor tactical vision
        return {'vision': 0.6, 'audio': 0.4}      # Balanced normal play

    async def _process_vision(self, video, weight):
        # Adaptive inference: skip frames if weight < threshold
        if weight > 0.7:
            return await self.vision_model.process(video, quality='full')
        return await self.vision_model.process(video, quality='fast')

    async def _process_audio(self, audio, weight):
        if weight > 0.6:
            return await self.audio_model.process(audio, include_crowd_context=True)
        return await self.audio_model.process(audio, include_crowd_context=False)

    def _hierarchical_merge(self, results, weights):
        # Confidence-weighted fusion
        merged = {}
        for modality, result in results.items():
            if result and result['confidence'] * weights[modality] > 0.5:
                merged[modality] = result
        return merged
